117	export function createTogetherAI(
118	  options: TogetherAIProviderSettings = {},
119	): TogetherAIProvider {
120	  const baseURL = withoutTrailingSlash(
121	    options.baseURL ?? 'https://api.together.xyz/v1/',
122	  );
123	  const getHeaders = () =>
124	    withUserAgentSuffix(
125	      {
126	        Authorization: `Bearer ${loadApiKey({
127	          apiKey: options.apiKey ?? loadDeprecatedApiKey(),
128	          environmentVariableName: 'TOGETHER_API_KEY',
129	          description: 'TogetherAI',
130	        })}`,
131	        ...options.headers,
132	      },
133	      `ai-sdk/togetherai/${VERSION}`,
134	    );
135	
136	  interface CommonModelConfig {
137	    provider: string;
138	    url: ({ path }: { path: string }) => string;
139	    headers: () => Record<string, string>;
140	    fetch?: FetchFunction;
141	  }
142	
143	  const getCommonModelConfig = (modelType: string): CommonModelConfig => ({
144	    provider: `togetherai.${modelType}`,
145	    url: ({ path }) => `${baseURL}${path}`,
146	    headers: getHeaders,
147	    fetch: options.fetch,
148	  });
149	
150	  const createChatModel = (modelId: TogetherAIChatModelId) => {
151	    return new OpenAICompatibleChatLanguageModel(
152	      modelId,
153	      getCommonModelConfig('chat'),
154	    );
155	  };
156	
157	  const createCompletionModel = (modelId: TogetherAICompletionModelId) =>
158	    new OpenAICompatibleCompletionLanguageModel(
159	      modelId,
160	      getCommonModelConfig('completion'),
161	    );
162	
163	  const createEmbeddingModel = (modelId: TogetherAIEmbeddingModelId) =>
164	    new OpenAICompatibleEmbeddingModel(
165	      modelId,
166	      getCommonModelConfig('embedding'),
167	    );
168	
169	  const createImageModel = (modelId: TogetherAIImageModelId) =>
170	    new TogetherAIImageModel(modelId, {
171	      ...getCommonModelConfig('image'),
172	      baseURL: baseURL ?? 'https://api.together.xyz/v1/',
173	    });
174	
175	  const createRerankingModel = (modelId: TogetherAIRerankingModelId) =>
176	    new TogetherAIRerankingModel(modelId, {
177	      ...getCommonModelConfig('reranking'),
178	      baseURL: baseURL ?? 'https://api.together.xyz/v1/',
179	    });
180	
181	  const provider = (modelId: TogetherAIChatModelId) => createChatModel(modelId);
182	
183	  provider.specificationVersion = 'v3' as const;
184	  provider.completionModel = createCompletionModel;
185	  provider.languageModel = createChatModel;
186	  provider.chatModel = createChatModel;
187	  provider.embeddingModel = createEmbeddingModel;
188	  provider.textEmbeddingModel = createEmbeddingModel;
189	  provider.image = createImageModel;
190	  provider.imageModel = createImageModel;
191	  provider.reranking = createRerankingModel;
192	  provider.rerankingModel = createRerankingModel;
193	
194	  return provider;
195	}
