8	} from './perplexity-language-model-prompt';
9	import { convertUint8ArrayToBase64 } from '@ai-sdk/provider-utils';
10	
11	export function convertToPerplexityMessages(
12	  prompt: LanguageModelV3Prompt,
13	): PerplexityPrompt {
14	  const messages: PerplexityPrompt = [];
15	
16	  for (const { role, content } of prompt) {
17	    switch (role) {
18	      case 'system': {
19	        messages.push({ role: 'system', content });
20	        break;
21	      }
22	
23	      case 'user':
24	      case 'assistant': {
25	        const hasMultipartContent = content.some(
26	          part =>
27	            (part.type === 'file' && part.mediaType.startsWith('image/')) ||
28	            (part.type === 'file' && part.mediaType === 'application/pdf'),
29	        );
30	
31	        const messageContent = content
32	          .map((part, index) => {
33	            switch (part.type) {
34	              case 'text': {
35	                return {
36	                  type: 'text',
37	                  text: part.text,
38	                };
39	              }
40	              case 'file': {
41	                if (part.mediaType === 'application/pdf') {
42	                  return part.data instanceof URL
43	                    ? {
44	                        type: 'file_url',
45	                        file_url: {
46	                          url: part.data.toString(),
47	                        },
48	                        file_name: part.filename,
49	                      }
50	                    : {
51	                        type: 'file_url',
52	                        file_url: {
53	                          url:
54	                            typeof part.data === 'string'
55	                              ? part.data
56	                              : convertUint8ArrayToBase64(part.data),
57	                        },
58	                        file_name: part.filename || `document-${index}.pdf`,
59	                      };
60	                } else if (part.mediaType.startsWith('image/')) {
61	                  return part.data instanceof URL
62	                    ? {
63	                        type: 'image_url',
64	                        image_url: {
65	                          url: part.data.toString(),
66	                        },
67	                      }
68	                    : {
69	                        type: 'image_url',
70	                        image_url: {
71	                          url: `data:${part.mediaType ?? 'image/jpeg'};base64,${
72	                            typeof part.data === 'string'
73	                              ? part.data
74	                              : convertUint8ArrayToBase64(part.data)
75	                          }`,
76	                        },
77	                      };
78	                }
79	              }
80	            }
81	          })
82	          .filter(Boolean) as PerplexityMessageContent[];
83	        messages.push({
84	          role,
85	          content: hasMultipartContent
86	            ? messageContent
87	            : messageContent
88	                .filter(part => part.type === 'text')
89	                .map(part => part.text)
90	                .join(''),
91	        });
92	        break;
93	      }
94	      case 'tool': {
95	        throw new UnsupportedFunctionalityError({
96	          functionality: 'Tool messages',
97	        });
98	      }
99	      default: {
100	        const _exhaustiveCheck: never = role;
101	        throw new Error(`Unsupported role: ${_exhaustiveCheck}`);
102	      }
103	    }
104	  }
105	
106	  return messages;
107	}
