import type { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
import type { InferSchema, Resolvable } from '@ai-sdk/provider-utils';
import {
  FetchFunction,
  combineHeaders,
  createJsonErrorResponseHandler,
  createJsonResponseHandler,
  lazySchema,
  parseProviderOptions,
  postJsonToApi,
  resolve,
  zodSchema,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';
import { PixelArtImageModelId } from './pixelart-image-settings';

interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers?: Resolvable<Record<string, string | undefined>>;
  fetch?: FetchFunction;
  _internal?: {
    currentDate?: () => Date;
  };
}

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 1;

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: PixelArtImageModelId,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  private async getArgs({
    prompt,
    size,
    aspectRatio,
    seed,
    providerOptions,
  }: Parameters<ImageModelV3['doGenerate']>[0]) {
    const warnings: Array<SharedV3Warning> = [];

    if (aspectRatio != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'aspectRatio',
        details:
          'PixelArt does not support aspectRatio. Use the size parameter to control image dimensions.',
      });
    }

    const pixelArtOptions = await parseProviderOptions({
      provider: 'pixelArt',
      providerOptions,
      schema: pixelArtImageModelOptionsSchema,
    });

    const body: Record<string, unknown> = {
      model: this.modelId,
      prompt,
      seed,
      size,
      style: pixelArtOptions?.style,
      pixel_density: pixelArtOptions?.pixelDensity,
    };

    return { body, warnings };
  }

  async doGenerate(
    options: Parameters<ImageModelV3['doGenerate']>[0],
  ): Promise<Awaited<ReturnType<ImageModelV3['doGenerate']>>> {
    const { body, warnings } = await this.getArgs(options);

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();
    const { value, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/images/generate`,
      headers: combineHeaders(
        await resolve(this.config.headers),
        options.headers,
      ),
      body,
      failedResponseHandler: pixelArtFailedResponseHandler,
      successfulResponseHandler: createJsonResponseHandler(
        pixelArtImageResponseSchema,
      ),
      abortSignal: options.abortSignal,
      fetch: this.config.fetch,
    });

    return {
      images: value.images.map(image => base64ToUint8Array(image.b64_json)),
      warnings,
      response: {
        modelId: this.modelId,
        timestamp: currentDate,
        headers: responseHeaders,
      },
      providerMetadata: {
        pixelArt: {
          images: value.images.map(image => ({
            ...(image.width != null && { width: image.width }),
            ...(image.height != null && { height: image.height }),
          })),
        },
      },
    };
  }
}

export const pixelArtImageModelOptionsSchema = lazySchema(() =>
  zodSchema(
    z.object({
      /**
       * Visual style of the generated image.
       * - 'pixel': Classic pixel art style
       * - 'retro': Retro-inspired pixel aesthetic
       * - '8bit': 8-bit video game style
       */
      style: z.enum(['pixel', 'retro', '8bit']).optional(),

      /**
       * Pixel density of the generated image (1–10).
       * Higher values produce finer pixel grids.
       */
      pixelDensity: z.number().int().min(1).max(10).optional(),
    }),
  ),
);

export type PixelArtImageModelOptions = InferSchema<
  typeof pixelArtImageModelOptionsSchema
>;

function base64ToUint8Array(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const bytes = new Uint8Array(binaryString.length);
  for (let i = 0; i < binaryString.length; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

const pixelArtImageSchema = z.object({
  b64_json: z.string(),
  width: z.number().nullish(),
  height: z.number().nullish(),
});

const pixelArtImageResponseSchema = z.object({
  images: z.array(pixelArtImageSchema),
});

const pixelArtErrorSchema = z.object({
  error: z
    .object({
      message: z.string().optional(),
      code: z.string().optional(),
    })
    .optional(),
  message: z.string().optional(),
});

const pixelArtFailedResponseHandler = createJsonErrorResponseHandler({
  errorSchema: pixelArtErrorSchema,
  errorToMessage: error =>
    error.error?.message ?? error.message ?? 'Unknown PixelArt error',
});

