import { FetchFunction } from '@ai-sdk/provider-utils';
import { createTestServer } from '@ai-sdk/test-server/with-vitest';
import { describe, expect, it } from 'vitest';
import { PixelArtImageModel } from './pixelart-image-model';

const prompt = 'A tiny pixel warrior with a sword';

// A minimal 1x1 white PNG encoded as base64
const TEST_B64 = btoa('fake-png-bytes');

function createBasicModel({
  headers,
  fetch,
  currentDate,
}: {
  headers?: () => Record<string, string | undefined>;
  fetch?: FetchFunction;
  currentDate?: () => Date;
} = {}) {
  return new PixelArtImageModel('pixelart-v1', {
    provider: 'pixelart.image',
    baseURL: 'https://api.example.com/v1',
    headers: headers ?? (() => ({ Authorization: 'Bearer test-key' })),
    fetch,
    _internal: { currentDate },
  });
}

describe('PixelArtImageModel', () => {
  const server = createTestServer({
    'https://api.example.com/v1/images/generate': {
      response: {
        type: 'json-value',
        body: {
          images: [{ b64_json: TEST_B64 }],
        },
      },
    },
  });

  describe('doGenerate', () => {
    it('sends prompt and model in request body', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
      });

      expect(await server.calls[0].requestBodyJson).toMatchObject({
        model: 'pixelart-v1',
        prompt,
      });
    });

    it('sends size and seed when provided', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: '512x512',
        aspectRatio: undefined,
        seed: 42,
        providerOptions: {},
      });

      expect(await server.calls[0].requestBodyJson).toMatchObject({
        size: '512x512',
        seed: 42,
      });
    });

    it('sends style and pixelDensity from providerOptions', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {
          pixelArt: {
            style: 'retro',
            pixelDensity: 5,
          },
        },
      });

      expect(await server.calls[0].requestBodyJson).toMatchObject({
        style: 'retro',
        pixel_density: 5,
      });
    });

    it('ignores unknown provider options', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {
          pixelArt: {
            style: '8bit',
            unknownOption: 'ignored',
          },
        },
      });

      const body = await server.calls[0].requestBodyJson;
      expect(body).toMatchObject({ style: '8bit' });
      expect(body).not.toHaveProperty('unknownOption');
    });

    it('warns on unsupported aspectRatio', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: '16:9',
        seed: undefined,
        providerOptions: {},
      });

      expect(result.warnings).toMatchInlineSnapshot(`
        [
          {
            "details": "PixelArt does not support aspectRatio. Use the size parameter to control image dimensions.",
            "feature": "aspectRatio",
            "type": "unsupported",
          },
        ]
      `);
    });

    it('returns no warnings when aspectRatio is not provided', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: '256x256',
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
      });

      expect(result.warnings).toHaveLength(0);
    });

    it('decodes base64 image and returns Uint8Array', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
      });

      expect(result.images).toHaveLength(1);
      expect(result.images[0]).toBeInstanceOf(Uint8Array);
      // The decoded bytes should match our fake content
      const decoded = new TextDecoder().decode(result.images[0]);
      expect(decoded).toBe('fake-png-bytes');
    });

    it('includes width and height in providerMetadata when present', async () => {
      server.urls['https://api.example.com/v1/images/generate'].response = {
        type: 'json-value',
        body: {
          images: [{ b64_json: TEST_B64, width: 256, height: 256 }],
        },
      };

      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
      });

      expect(result.providerMetadata?.pixelArt.images[0]).toMatchObject({
        width: 256,
        height: 256,
      });
    });

    it('omits width and height from providerMetadata when absent', async () => {
      server.urls['https://api.example.com/v1/images/generate'].response = {
        type: 'json-value',
        body: {
          images: [{ b64_json: TEST_B64 }],
        },
      };

      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
      });

      const meta = result.providerMetadata?.pixelArt.images[0];
      expect(meta).toBeDefined();
      expect(meta).not.toHaveProperty('width');
      expect(meta).not.toHaveProperty('height');
    });

    it('includes timestamp, headers, and modelId in response', async () => {
      const testDate = new Date('2025-06-01T00:00:00Z');
      const model = createBasicModel({ currentDate: () => testDate });

      const result = await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
      });

      expect(result.response).toStrictEqual({
        timestamp: testDate,
        modelId: 'pixelart-v1',
        headers: expect.any(Object),
      });
    });

    it('merges provider and request headers', async () => {
      const model = createBasicModel({
        headers: () => ({
          Authorization: 'Bearer test-key',
          'X-Provider-Header': 'provider-value',
        }),
      });

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        headers: { 'X-Request-Header': 'request-value' },
      });

      expect(server.calls[0].requestHeaders).toMatchObject({
        authorization: 'Bearer test-key',
        'x-provider-header': 'provider-value',
        'x-request-header': 'request-value',
      });
    });

    it('handles API error responses', async () => {
      server.urls['https://api.example.com/v1/images/generate'].response = {
        type: 'error',
        status: 422,
        body: JSON.stringify({
          error: { message: 'Invalid style value', code: 'validation_error' },
        }),
      };

      const model = createBasicModel();

      await expect(
        model.doGenerate({
          prompt,
          files: undefined,
          mask: undefined,
          n: 1,
          size: undefined,
          aspectRatio: undefined,
          seed: undefined,
          providerOptions: {},
        }),
      ).rejects.toMatchObject({
        message: 'Invalid style value',
        statusCode: 422,
      });
    });

    it('uses correct HTTP method and endpoint URL', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
      });

      expect(server.calls[0].requestMethod).toBe('POST');
      expect(server.calls[0].requestUrl).toBe(
        'https://api.example.com/v1/images/generate',
      );
    });
  });

  describe('constructor', () => {
    it('exposes correct provider and model information', () => {
      const model = createBasicModel();

      expect(model.provider).toBe('pixelart.image');
      expect(model.modelId).toBe('pixelart-v1');
      expect(model.specificationVersion).toBe('v3');
      expect(model.maxImagesPerCall).toBe(1);
    });
  });
});

