import { describe, expect, it } from 'vitest';
import { createPixelArt } from './pixelart-provider';

const TEST_B64 = btoa('fake-png-bytes');

const server = createTestServer({
  'https://api.example.com/v1/images/generate': {
    response: {
      type: 'json-value',
      body: {
        images: [{ b64_json: TEST_B64 }],
      },
